#include <bits/stdc++.h>
using namespace std;
long long n,d,a[100005],s[100005],sum[100005],more,ans;
int main(){
	cin>>n>>d;
	for(int i=1;i<n;i++)
		cin>>s[i];
	for(int i=1;i<=n;i++)
		cin>>a[i];
	int min=a[1];
	int k=1;
	for(int i=1;i<n;i++){
		if(a[i]>min){
			sum[k]+=s[i];
		}else{
			k=i;
			min=a[i];
			sum[i]+=s[i];
		}
	}
	for(int i=1;i<=n;i++){
		ans+=ceil(sum[i]*1.0/d)*a[i];
		more+=ceil(sum[i]*1.0/d)*d-sum[i];
		if(more>=d){
			more-=d;
			ans-=a[i];
		}
	}
	cout<<ans;
	return 0;
}
